const BASE_URL = 'https://shopflow.io';

// ── Shared helpers ────────────────────────────────────────────
async function login(page: Page) {
  await page.goto(`${BASE_URL}/login`);
  await page.locator('[data-testid="username-input"]').fill('johnsonjoshua');
  await page.locator('[data-testid="password-input"]').fill('Test@3218');
  await page.locator('[data-testid="login-btn"]').click();
  await expect(page).toHaveURL(/home|dashboard/);
}

/**
 * TC-U01 — [Positive]
 * Area     : Search
 * Scenario : Verify search returns relevant results for a valid keyword
 * AC       : AC2
 */
test('TC-U01: Verify search returns relevant results for a valid keyword', async ({ page }) => {
  // Precondition: authenticated user
  await login(page);

  // Navigate to search
  await page.goto(`${BASE_URL}/search`);
  await page.locator('[data-testid="search-input"]').fill('laptop');
  await page.locator('[data-testid="search-btn"]').click();

  // Assert results contain name, price and image
  const firstResult = page.locator('[data-testid="product-card"]').first();
  await expect(firstResult).toBeVisible();
  await expect(firstResult.locator('[data-testid="product-name"]')).toBeVisible();
  await expect(firstResult.locator('[data-testid="product-price"]')).toBeVisible();
  await expect(firstResult.locator('[data-testid="product-image"]')).toBeVisible();
});

